// WalletCarousel.js - Carrusel profesional con ciclo infinito
// Puedes navegar indefinidamente hacia izquierda/derecha

import React, { useState, useRef, useEffect } from 'react';
import WalletCard from './WalletCard';
import './WalletCarousel.css';

const WalletCarousel = ({ wallets }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [cardsPerView, setCardsPerView] = useState(3);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const carouselTrackRef = useRef(null);
  
  // Para el ciclo infinito, duplicamos las billeteras (principio + final)
  const extendedWallets = [...wallets, ...wallets, ...wallets];
  const totalWallets = wallets.length;
  
  // Detectar el tamaño de pantalla
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 640) {
        setCardsPerView(1);
      } else if (window.innerWidth < 1024) {
        setCardsPerView(2);
      } else {
        setCardsPerView(3);
      }
    };
    
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);
  
  // Calcular el índice real para el ciclo infinito
  const getRealIndex = (index) => {
    const realIndex = ((index % totalWallets) + totalWallets) % totalWallets;
    return realIndex;
  };
  
  // Navegar a la siguiente diapositiva
  const goToNext = () => {
    if (isTransitioning) return;
    
    setIsTransitioning(true);
    setCurrentIndex(prev => {
      const newIndex = prev + 1;
      
      // Si llegamos al final del array extendido, reseteamos sin transición
      if (newIndex >= extendedWallets.length - cardsPerView) {
        setTimeout(() => {
          setIsTransitioning(false);
          // Resetear sin animación al inicio
          if (carouselTrackRef.current) {
            carouselTrackRef.current.style.transition = 'none';
            setCurrentIndex(0);
            setTimeout(() => {
              if (carouselTrackRef.current) {
                carouselTrackRef.current.style.transition = 'transform 0.4s cubic-bezier(0.2, 0.9, 0.4, 1.1)';
              }
            }, 50);
          }
        }, 300);
        return newIndex;
      }
      
      setTimeout(() => setIsTransitioning(false), 300);
      return newIndex;
    });
  };
  
  // Navegar a la diapositiva anterior
  const goToPrevious = () => {
    if (isTransitioning) return;
    
    setIsTransitioning(true);
    setCurrentIndex(prev => {
      const newIndex = prev - 1;
      
      // Si llegamos al inicio del array extendido
      if (newIndex < 0) {
        const lastValidIndex = extendedWallets.length - cardsPerView - cardsPerView;
        setTimeout(() => {
          setIsTransitioning(false);
          if (carouselTrackRef.current) {
            carouselTrackRef.current.style.transition = 'none';
            setCurrentIndex(lastValidIndex);
            setTimeout(() => {
              if (carouselTrackRef.current) {
                carouselTrackRef.current.style.transition = 'transform 0.4s cubic-bezier(0.2, 0.9, 0.4, 1.1)';
              }
            }, 50);
          }
        }, 300);
        return newIndex;
      }
      
      setTimeout(() => setIsTransitioning(false), 300);
      return newIndex;
    });
  };
  
  // Ir a un slide específico (por los dots)
  const goToSlide = (index) => {
    if (isTransitioning) return;
    setIsTransitioning(true);
    setCurrentIndex(index * cardsPerView);
    setTimeout(() => setIsTransitioning(false), 300);
  };
  
  // Indicadores de posición actual (para los dots)
  const getCurrentDotIndex = () => {
    const rawIndex = Math.floor(currentIndex / cardsPerView);
    return ((rawIndex % totalWallets) + totalWallets) % totalWallets;
  };
  
  return (
    <div className="carousel-wrapper">
      <div className="carousel-container">
        <button 
          className="carousel-nav-btn prev" 
          onClick={goToPrevious}
        >
          <span className="nav-icon">←</span>
        </button>
        
        <div className="carousel-viewport">
          <div 
            ref={carouselTrackRef}
            className="carousel-track-modern"
            style={{
              transform: `translateX(-${currentIndex * (100 / cardsPerView)}%)`,
              transition: isTransitioning ? 'transform 0.4s cubic-bezier(0.2, 0.9, 0.4, 1.1)' : 'none'
            }}
          >
            {extendedWallets.map((wallet, idx) => (
              <div 
                key={`${wallet.id}-${idx}`} 
                className="carousel-slide"
                style={{ flex: `0 0 ${100 / cardsPerView}%` }}
              >
                <WalletCard
                  name={wallet.name}
                  type={wallet.type}
                  balance={wallet.balance}
                />
              </div>
            ))}
          </div>
        </div>
        
        <button 
          className="carousel-nav-btn next" 
          onClick={goToNext}
        >
          <span className="nav-icon">→</span>
        </button>
      </div>
      
      {/* Indicadores (dots) */}
      <div className="carousel-dots">
        {wallets.map((_, idx) => (
          <button
            key={idx}
            className={`carousel-dot ${getCurrentDotIndex() === idx ? 'active' : ''}`}
            onClick={() => goToSlide(idx)}
          />
        ))}
      </div>
    </div>
  );
};

export default WalletCarousel;
